class Solution:
    def canChoose(self, groups, nums):
        n = len(nums)
        pos = 0
        for g in groups:
            m = len(g)
            found = -1
            j = pos
            while j + m <= n:
                if nums[j:j + m] == g:
                    found = j
                    break
                j += 1
            if found == -1:
                return False
            pos = found + m
        return True

