class Solution:
    def canChoose(self, groups, nums):
        n = len(nums)
        i = 0
        gi = 0
        while gi < len(groups) and i < n:
            g = groups[gi]
            m = len(g)
            if i + m <= n and nums[i:i + m] == g:
                i += m
                gi += 1
            else:
                i += 1
        return gi == len(groups)

