var canChoose = function(groups, nums) {
    const n = nums.length;
    let i = 0, gi = 0;
    const matchAt = (g, start) => {
        if (start + g.length > n) return false;
        for (let k = 0; k < g.length; k++) {
            if (nums[start + k] !== g[k]) return false;
        }
        return true;
    };
    while (gi < groups.length && i < n) {
        if (matchAt(groups[gi], i)) {
            i += groups[gi].length;
            gi++;
        } else {
            i++;
        }
    }
    return gi === groups.length;
};
